1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const FOLLOWUP_DISCOUNT_RATE = 0.15;
28	
29	const sum = (values: number[]): number =>
30	  values.reduce((total, value) => total + value, 0);
31	
32	// Policy-wide discounts, each a rate applied to the policy base premium when its
33	// condition holds. Parallels mainItemSurchargeRates as the single source of
34	// truth for the discount model.
35	const policyWideDiscountRates = (
36	  customer: Customer,
37	  contractIndex: number,
38	): number[] => [
39	  ...(customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
40	    ? [LOYALTY_DISCOUNT_RATE]
41	    : []),
42	  ...(contractIndex >= 1 ? [FOLLOWUP_DISCOUNT_RATE] : []),
43	];
44	
45	// Item-specific surcharges, each a rate applied additively to the base premium
46	// when its condition holds. First insurance always applies; the rest are
47	// conditional on the item.
48	const mainItemSurchargeRates = (item: Item): number[] => [
49	  FIRST_INSURANCE_RATE,
50	  ...(item.cursed ? [CURSE_SURCHARGE_RATE] : []),
51	  ...((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
52	    ? [HIGH_ENCHANTMENT_RATE]
53	    : []),
54	];
55	
56	// The additive surcharge model: a base premium scaled by 1 plus the sum of all
57	// applicable rates. Shared by every premium path (single source of truth).
58	const applyRates = (basePremium: number, rates: number[]): number =>
59	  basePremium * (1 + sum(rates));
60	
61	// A main item's raw base premium, before any surcharges — the basis for both the
62	// surcharged premium and the policy-wide discount.
63	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type];
64	
65	// A main item's premium: its base premium with all applicable surcharge rates applied.
66	const mainItemPremium = (item: Item): number =>
67	  applyRates(mainItemBase(item), mainItemSurchargeRates(item));
68	
69	const COMPONENT_TYPES = ["rune", "moonstone"];
70	const COMPONENT_BASE_PREMIUM = 25;
71	const COMPONENT_BLOCK_SIZE = 3;
72	const COMPONENT_BLOCK_PREMIUM = 60;
73	
74	const isComponent = (item: Item): boolean =>
75	  COMPONENT_TYPES.includes(item.type);
76	
77	// Base premium for `count` alike components: a block premium applies only for
78	// exactly one block's worth (3) of components; otherwise each is priced individually.
79	const componentBasePremium = (count: number): number => {
80	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
81	  return count * COMPONENT_BASE_PREMIUM;
82	};
83	
84	const countByType = (items: Item[]): Map<string, number> => {
85	  const counts = new Map<string, number>();
86	  for (const item of items) {
87	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
88	  }
89	  return counts;
90	};
91	
92	// The block rule is per-type ("alike" = same type), so price each type's count
93	// independently. componentBasePremium(count) is the raw per-type base; both the
94	// surcharged premium and the policy-wide raw base build on it.
95	const componentTypeBases = (componentItems: Item[]): number[] =>
96	  [...countByType(componentItems).values()].map(componentBasePremium);
97	
98	// Every item is treated as first insurance today, so the surcharge is applied
99	// uniformly to each base premium, using the same additive rate as main items.
100	const withFirstInsurance = (basePremium: number): number =>
101	  applyRates(basePremium, [FIRST_INSURANCE_RATE]);
102	
103	const componentItemsPremium = (componentItems: Item[]): number =>
104	  sum(componentTypeBases(componentItems).map(withFirstInsurance));
105	
106	// The policy base premium is the sum of raw item base premiums (no item
107	// surcharges); policy-wide discounts are percentages of this amount.
108	const policyBasePremium = (mainItems: Item[], componentItems: Item[]): number =>
109	  sum(mainItems.map(mainItemBase)) + sum(componentTypeBases(componentItems));
110	
111	// Round up in MHPCO's favour, guarding against floating-point noise
112	// (e.g. 197.50000000001 should still round to 198, not 199).
113	const roundUpInMHPCOFavor = (amount: number): number =>
114	  Math.ceil(Number(amount.toFixed(6)));
115	
116	export const quote = (
117	  items: Item[],
118	  customer: Customer,
119	  contractIndex: number,
120	): number => {
121	  const mainItems = items.filter((item) => !isComponent(item));
122	  const componentItems = items.filter((item) => isComponent(item));
123	
124	  const mainPremium = sum(mainItems.map(mainItemPremium));
125	  const componentPremium = componentItemsPremium(componentItems);
126	
127	  const policyWideDiscount =
128	    sum(policyWideDiscountRates(customer, contractIndex)) *
129	    policyBasePremium(mainItems, componentItems);
130	
131	  return roundUpInMHPCOFavor(
132	    mainPremium + componentPremium - policyWideDiscount + PROCESSING_FEE,
133	  );
134	};
135	
136	export const claim = (): number => {
137	  return undefined as unknown as number;
138	};
